//! 构建脚本
//!
//! 负责设置链接脚本路径
//! 启动汇编代码使用 Rust 的 global_asm! 引入

use std::env;
use std::path::PathBuf;

fn main() {
    let manifest_dir = env::var("CARGO_MANIFEST_DIR").unwrap();
    let project_root = PathBuf::from(&manifest_dir).parent().unwrap().to_path_buf();

    let target = env::var("TARGET").unwrap();

    // 根据目标架构选择 boot 目录
    let boot_dir = if target.contains("riscv64") {
        "riscv64"
    } else if target.contains("x86_64") {
        "amd64"
    } else if target.contains("loongarch64") {
        "loongarch64"
    } else {
        panic!("Unsupported target: {}", target);
    };

    let boot_path = project_root.join("kernel").join("src").join("arch").join(boot_dir).join("boot");
    let linker_path = boot_path.join("linker.ld");

    // 告诉 cargo 链接脚本路径
    println!("cargo:rustc-link-arg=-T{}", linker_path.display());

    // 监控文件变化
    println!("cargo:rerun-if-changed={}", linker_path.display());
    println!("cargo:rerun-if-changed=build.rs");
    // 监控 init 用户程序变化 (include_bytes! 不触发 cargo 重编译)
    let init_path = project_root.join("user").join("build").join("init");
    println!("cargo:rerun-if-changed={}", init_path.display());
}

# OSKernel Makefile
#
# 用法:
#   make              - 编译 riscv64 (默认)
#   make ARCH=amd64   - 编译 amd64
#   make run          - 编译并运行
#   make debug        - 编译并以调试模式运行
#   make test         - 用比赛测试镜像启动 QEMU
#   make clean        - 清理构建产物
#
# 比赛评测:
#   make all          - 生成 kernel-rv 和 kernel-la (比赛评测入口)

# 默认架构
ARCH ?= riscv64

# 辅助: Make 函数中不能直接使用逗号
comma := ,

# 目录
ROOT_DIR    := $(shell pwd)
KERNEL_DIR  := $(ROOT_DIR)/kernel
BUILD_DIR   := $(ROOT_DIR)/build
TOOLS_DIR   := $(ROOT_DIR)/tools
USER_DIR    := $(ROOT_DIR)/user

# 根据架构设置 target triple
ifeq ($(ARCH), riscv64)
    TARGET := riscv64gc-unknown-none-elf
else ifeq ($(ARCH), amd64)
    TARGET := x86_64-unknown-none
else ifeq ($(ARCH), loongarch64)
    TARGET := loongarch64-unknown-none-elf
else
    $(error 不支持的架构: $(ARCH). 支持: riscv64, amd64, loongarch64)
endif

# Cargo 配置
CARGO_FLAGS := --release --target $(TARGET)

# 输出路径
CARGO_OUTPUT := $(KERNEL_DIR)/target/$(TARGET)/release/kernel
KERNEL_ELF   := $(BUILD_DIR)/$(ARCH)/kernel.elf

# ============================================================================
# 用户程序编译 (init 等, 内嵌进内核)
# ============================================================================

# 编译所有 user/ 下的程序, 并将产物复制到 user/build/
user-build:
	@echo "=========================================="
	@echo "  Building user programs"
	@echo "=========================================="
	@mkdir -p $(USER_DIR)/build
	@for prog in init hello tls_test; do \
		if [ -d $(USER_DIR)/$$prog ]; then \
			echo "[USER] Building $$prog ..."; \
			cd $(USER_DIR)/$$prog && \
			cargo build --release && \
			cp target/$(USER_TARGET)/release/$$prog $(USER_DIR)/build/$$prog && \
			echo "[OK] $$prog -> user/build/$$prog"; \
		fi; \
	done

# ============================================================================
# 主要目标
# ============================================================================

# 比赛测试镜像
TESTSUITS_DIR := $(TOOLS_DIR)/testsuits-for-oskernel
SDCARD_RV     := $(TESTSUITS_DIR)/sdcard-rv.img
SDCARD_RV_XZ  := $(TESTSUITS_DIR)/sdcard-rv.img.xz
DISK_IMG      := $(ROOT_DIR)/disk.img
BIOS_IMG      := $(TOOLS_DIR)/firmware/rustsbi-qemu.bin

# QEMU 参数
QEMU_MEM  ?= 128M
QEMU_SMP  ?= 1

# 用户程序 target triple (裸机静态 ELF)
USER_TARGET := riscv64gc-unknown-none-elf

.PHONY: all build run debug clean test user-build docker

# --- 比赛评测入口 ---
# 评测系统会过滤隐藏目录, 故提交时将 .cargo 改名为 cargo-config,
# all 目标在构建前恢复它.
all: user-build
	@# 恢复被评测系统过滤的隐藏目录
	@if [ -d $(KERNEL_DIR)/cargo-config ] && [ ! -d $(KERNEL_DIR)/.cargo ]; then \
		cp -r $(KERNEL_DIR)/cargo-config $(KERNEL_DIR)/.cargo; \
	fi
	@echo "=========================================="
	@echo "  Building OSKernel for competition"
	@echo "=========================================="
	@$(MAKE) ARCH=riscv64 build
	@cp $(BUILD_DIR)/riscv64/kernel.elf $(ROOT_DIR)/kernel-rv
	@echo "[OK] kernel-rv generated"
	@# loongarch64 暂未实现, 生成占位文件 (避免评测系统报错)
	@# 实现后取消下面的注释并删除 touch 行:
	@# $(MAKE) ARCH=loongarch64 build
	@# cp $(BUILD_DIR)/loongarch64/kernel.elf $(ROOT_DIR)/kernel-la
	@touch $(ROOT_DIR)/kernel-la
	@echo "[OK] kernel-la generated (placeholder)"
	@echo ""
	@echo "=========================================="
	@echo "  Competition build complete"
	@echo "=========================================="



# 编译内核 (先编译用户程序, 因为 init ELF 通过 include_bytes! 内嵌进内核)
build: user-build
	@echo "=========================================="
	@echo "  Building OSKernel for $(ARCH)"
	@echo "=========================================="
	@mkdir -p $(BUILD_DIR)/$(ARCH)
	cd $(KERNEL_DIR) && cargo build $(CARGO_FLAGS)
	@cp $(CARGO_OUTPUT) $(KERNEL_ELF)
	@echo ""
	@echo "[OK] 编译完成: $(KERNEL_ELF)"

# 运行
run: build
	$(TOOLS_DIR)/run-qemu.sh -a $(ARCH) -k $(KERNEL_ELF)

# 调试模式运行
debug: build
	$(TOOLS_DIR)/run-qemu.sh -a $(ARCH) -k $(KERNEL_ELF) -d

# 无图形界面运行
run-nographic: build
	$(TOOLS_DIR)/run-qemu.sh -a $(ARCH) -k $(KERNEL_ELF) -n

# ============================================================================
# 比赛测试 (使用 sdcard 镜像)
# ============================================================================

# # 解压 sdcard 镜像 (只在 .img 不存在时执行)
# $(SDCARD_RV): $(SDCARD_RV_XZ)
# 	@echo "[INFO] 解压 sdcard-rv.img.xz ..."
# 	xz -dk $(SDCARD_RV_XZ)
# 	@echo "[OK] sdcard-rv.img 已生成 ($(shell du -h $(SDCARD_RV) 2>/dev/null | cut -f1))"

# make test: 编译内核并用比赛 QEMU 命令格式启动, 挂载测试用例磁盘
test: build $(SDCARD_RV)
	@echo "=========================================="
	@echo "  Running competition tests (riscv64)"
	@echo "=========================================="
	@echo "  Kernel:  $(KERNEL_ELF)"
	@echo "  SDCard:  $(SDCARD_RV)"
	@echo "  Memory:  $(QEMU_MEM)  SMP: $(QEMU_SMP)"
	@echo "=========================================="
	qemu-system-riscv64 \
		-machine virt \
		-kernel $(KERNEL_ELF) \
		-m $(QEMU_MEM) \
		-nographic \
		-smp $(QEMU_SMP) \
		-bios $(BIOS_IMG) \
		-drive file=$(SDCARD_RV),if=none,format=raw,id=x0 \
		-device virtio-blk-device,drive=x0,bus=virtio-mmio-bus.0 \
		-no-reboot \
		-device virtio-net-device,netdev=net \
		-netdev user,id=net \
		-rtc base=utc \
		$(if $(wildcard $(DISK_IMG)), \
			-drive file=$(DISK_IMG)$(comma)if=none$(comma)format=raw$(comma)id=x1 \
			-device virtio-blk-device$(comma)drive=x1$(comma)bus=virtio-mmio-bus.1)

# 清理
clean:
	cd $(KERNEL_DIR) && cargo clean
	rm -rf $(BUILD_DIR)/*/kernel.elf

# ============================================================================
# 调试与分析
# ============================================================================

# GDB 连接 (需要先运行 make debug)
gdb: build
	$(TOOLS_DIR)/gdb-connect.sh -a $(ARCH)

# 运行分析并生成报告
analyze: build
	$(TOOLS_DIR)/analyze.sh -a $(ARCH) all

# 只运行追踪分析
analyze-trace: build
	$(TOOLS_DIR)/analyze.sh -a $(ARCH) trace

# 只运行函数调用分析
analyze-calls: build
	$(TOOLS_DIR)/analyze.sh -a $(ARCH) calls

# 只运行内存分析
analyze-memory: build
	$(TOOLS_DIR)/analyze.sh -a $(ARCH) memory

# ============================================================================
# 帮助
# ============================================================================

.PHONY: help
help:
	@echo "OSKernel 构建系统"
	@echo ""
	@echo "用法: make [TARGET] [ARCH=架构]"
	@echo ""
	@echo "构建:"
	@echo "  build         - 编译用户程序 + 内核 (默认)"
	@echo "  user-build    - 只编译用户程序 (user/build/ 下)"
	@echo "  clean         - 清理构建产物"
	@echo ""
	@echo "运行:"
	@echo "  run           - 编译并在 QEMU 中运行"
	@echo "  run-nographic - 无图形界面运行"
	@echo "  debug         - 以 GDB 调试模式运行 (等待连接)"
	@echo ""
	@echo "调试与分析:"
	@echo "  gdb           - 连接到 QEMU 调试会话 (需先 make debug)"
	@echo "  analyze       - 运行所有分析并生成报告"
	@echo "  analyze-trace - 执行追踪分析"
	@echo "  analyze-calls - 函数调用分析"
	@echo "  analyze-memory- 内存访问分析"
	@echo ""
	@echo "架构 (ARCH=):"
	@echo "  riscv64       - RISC-V 64-bit (默认)"
	@echo "  amd64         - x86-64"
	@echo "  loongarch64   - LoongArch 64-bit"
	@echo ""
	@echo "输出:"
	@echo "  内核:   build/<arch>/kernel.elf"
	@echo "  报告:   tools/reports/<timestamp>/"
	@echo ""
	@echo "示例:"
	@echo "  make                    # 编译 riscv64"
	@echo "  make run                # 编译并运行"
	@echo "  make debug              # 调试模式 (终端1)"
	@echo "  make gdb                # 连接 GDB  (终端2)"
	@echo "  make analyze            # 运行分析"


