//! 启动信息抽象。
//!
//! 优先解析 DTB 中的 `/memory` 节点构造启动内存信息；若解析失败，
//! 则回退到 QEMU virt 平台 128MB RAM 的保底布局。

use crate::hal::fdt::{self, MemoryBlock};
use crate::mm::address::PhysAddr;

const PHYS_BASE: usize = 0x8000_0000;
