    fn _stack_top();
}

/// 启动阶段可见的物理内存类型。
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum MemoryKind {
    /// 可供内核或用户态分配的普通内存。
    Usable,
    /// 保留区域。
    Reserved,
    /// 内核镜像占用区域。
    Kernel,
    /// 启动栈占用区域。

